import{_ as e,c as t,o as r,ag as o}from"./chunks/framework.S-Qvb3wi.js";const p=JSON.parse('{"title":"준수 및 규제 요구 사항 명시","description":"","frontmatter":{},"headers":[],"relativePath":"kr/Compliance-and-Regulatory.md","filePath":"kr/Compliance-and-Regulatory.md"}'),n={name:"kr/Compliance-and-Regulatory.md"};function i(l,a,s,d,c,u){return r(),t("div",null,a[0]||(a[0]=[o('<h1 id="준수-및-규제-요구-사항-명시" tabindex="-1">준수 및 규제 요구 사항 명시 <a class="header-anchor" href="#준수-및-규제-요구-사항-명시" aria-label="Permalink to &quot;준수 및 규제 요구 사항 명시&quot;">​</a></h1><h2 id="regulation-s-준수-의무-이행" tabindex="-1">Regulation S 준수 의무 이행 <a class="header-anchor" href="#regulation-s-준수-의무-이행" aria-label="Permalink to &quot;Regulation S 준수 의무 이행&quot;">​</a></h2><p>DGrid 프리미엄 라이선스 판매 계획은 미국 Regulation S 관련 규정에 따라 엄격하게 수행됩니다. <strong>미국 내 거주자(U.S. persons)의 본 계획 참여는 엄격히 금지됩니다</strong>. 판매 공식 웹사이트, 모든 홍보 자료 및 사용자 인터페이스에 해당 참여 제한이 두드러지게 표시될 것입니다. 잠재적 참여자는 반드시 본 준수 요구 사항을 자세히 읽고 명확히 이해해야 합니다: <strong>DGrid 프리미엄 라이선스는 최초 발행 완료 후 12개월 이내에 양도, 재판매 또는任何 형태의 2차 유통을 할 수 없습니다</strong>. 이 규정을 위반할 경우 준수 의무 위반으로 간주됩니다.</p><h2 id="투명한-정보-공개-원칙" tabindex="-1">투명한 정보 공개 원칙 <a class="header-anchor" href="#투명한-정보-공개-원칙" aria-label="Permalink to &quot;투명한 정보 공개 원칙&quot;">​</a></h2><p>DGrid 프리미엄 판매와 관련된 모든 의사소통, 마케팅 자료 제작, 홍보 활동 및 소셜 미디어 게시 내용은 공개透明성을 핵심 원칙으로 합니다. 동시에 <strong>미국 내 거주자를 대상으로 한 타겟 마케팅 또는 판매 메시지는 엄격히 제외됩니다</strong>. 관련 정보 발행 과정에서 미국 대상을 포함할 수 있는 모든 내용 표현을 완전히 회피하여 Regulation S 준수 기준을 충족시키고 규제 위험을 효과적으로 낮춥니다. 한편, 참여자는 해당 관할 구역의 관련 규제 규정을 자체적으로 확인하고 준수 검토 책임을 독립적으로 부담해야 합니다. 자신의 참여 행위가 현지 법률 요구 사항에 완전히 부합하도록 보장하여 지역 규제 규정을 위반함으로써 발생할 수 있는 관련 위험을 피해야 합니다.</p>',5)]))}const g=e(n,[["render",i]]);export{p as __pageData,g as default};
